class Solution {
    public boolean isPrefixString(String s, String[] words) {
        int k = Math.min(s.length(), words.length);
        for (int i = 0; i < k; i++) {
            if (!words[i].equals(s.substring(0, i + 1))) {
                return false;
            }
        }
        return true;
    }
}
```

